# solution.py
"""Team Collaboration Manager.

A thread-safe, in-memory team collaboration system that manages users,
projects, tasks, messaging, performance dashboards, and report exports.

The public surface (classes, enums and the :class:`TeamCollaborationManager`
facade) is exercised by ``test_solution.py``. The implementation favours
explicit validation, defensive copying on every getter, and a single shared
lock so the manager and all of its sub-stores remain consistent under
concurrent access.
"""

import copy
import csv
import io
import threading
from dataclasses import dataclass
from datetime import datetime
from enum import Enum
from typing import Any, Callable, Dict, List, Optional, Tuple


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class TaskStatus(Enum):
    """Lifecycle states for a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    """Authorization role assigned to a user."""

    ADMIN = "admin"
    MANAGER = "manager"
    MEMBER = "member"
    VIEWER = "viewer"


class ReportFormat(Enum):
    """Supported export formats for a report."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Kinds of report the manager can produce."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an action."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with current state."""


# ---------------------------------------------------------------------------
# Domain entities
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    """A file attached to a message."""

    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class User:
    """A registered member of the workspace."""

    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    """A project owned by a user and scoped by a date range."""

    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    created_at: datetime


@dataclass
class Task:
    """A unit of work belonging to a project."""

    id: int
    project_id: int
    title: str
    status: TaskStatus
    assignee_id: Optional[int]
    deadline: Optional[datetime]
    started_at: Optional[datetime]
    completed_at: Optional[datetime]
    created_at: datetime


@dataclass
class Message:
    """A message posted against a project or a task."""

    id: int
    author_id: int
    body: str
    project_id: Optional[int]
    task_id: Optional[int]
    parent_id: Optional[int]
    attachments: List[Attachment]
    created_at: datetime
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    """Peer feedback given from one user to another."""

    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str
    task_id: Optional[int]
    created_at: datetime


# ---------------------------------------------------------------------------
# Internal stores
# ---------------------------------------------------------------------------
class _BaseStore:
    """Common base for the sub-stores; every store shares the manager lock."""

    def __init__(self, lock: "threading.RLock") -> None:
        self._lock = lock


class _UserStore(_BaseStore):
    def __init__(self, lock: "threading.RLock") -> None:
        super().__init__(lock)
        self.by_id: Dict[int, User] = {}
        self.by_username: Dict[str, int] = {}
        self.by_email: Dict[str, int] = {}


class _ProjectStore(_BaseStore):
    def __init__(self, lock: "threading.RLock") -> None:
        super().__init__(lock)
        self.by_id: Dict[int, Project] = {}


class _TaskStore(_BaseStore):
    def __init__(self, lock: "threading.RLock") -> None:
        super().__init__(lock)
        self.by_id: Dict[int, Task] = {}
        self.by_project: Dict[int, set] = {}
        self.by_assignee: Dict[int, set] = {}


class _MessageStore(_BaseStore):
    def __init__(self, lock: "threading.RLock") -> None:
        super().__init__(lock)
        self.by_id: Dict[int, Message] = {}
        self.by_project: Dict[int, set] = {}
        self.by_task: Dict[int, set] = {}


class _PerformanceStore(_BaseStore):
    def __init__(self, lock: "threading.RLock") -> None:
        super().__init__(lock)
        self.ratings_by_id: Dict[int, Rating] = {}
        self.ratings_by_ratee: Dict[int, set] = {}


class _ReportStore(_BaseStore):
    """Reports are computed on demand; this store only carries the lock."""


# ---------------------------------------------------------------------------
# Helpers
# ---------------------------------------------------------------------------
def _clone(obj: Any) -> Any:
    """Return a deep copy so callers can never mutate stored state."""

    return copy.deepcopy(obj)


def _is_nonempty_str(value: Any) -> bool:
    return isinstance(value, str) and bool(value.strip())


# ---------------------------------------------------------------------------
# Facade
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """Coordinates users, projects, tasks, messaging and reporting.

    All public methods are thread-safe. Entities returned from getters are
    deep copies, so mutating a returned object never affects internal state.
    """

    def __init__(self, now: Optional[Callable[[], datetime]] = None) -> None:
        self._now: Callable[[], datetime] = now if now is not None else datetime.now
        self._lock = threading.RLock()
        self._id_counter = 0

        self.users = _UserStore(self._lock)
        self.projects = _ProjectStore(self._lock)
        self.tasks = _TaskStore(self._lock)
        self.messages = _MessageStore(self._lock)
        self.performance = _PerformanceStore(self._lock)
        self.reports = _ReportStore(self._lock)

    # -- id generation ----------------------------------------------------
    def _next_id(self) -> int:
        self._id_counter += 1
        return self._id_counter

    # ------------------------------------------------------------------
    # User management
    # ------------------------------------------------------------------
    def register_user(
        self, username: str, email: str, role: UserRole = UserRole.MEMBER
    ) -> User:
        if not _is_nonempty_str(username):
            raise ValidationError("username must be a non-empty string")
        if not _is_nonempty_str(email):
            raise ValidationError("email must be a non-empty string")
        if "@" not in email:
            raise ValidationError("email must contain '@'")
        if not isinstance(role, UserRole):
            raise ValidationError("role must be a UserRole")

        username = username.strip()
        email = email.strip()
        with self._lock:
            if username in self.users.by_username:
                raise DuplicateError("username already exists")
            if email in self.users.by_email:
                raise DuplicateError("email already exists")
            uid = self._next_id()
            user = User(
                id=uid,
                username=username,
                email=email,
                role=role,
                created_at=self._now(),
            )
            self.users.by_id[uid] = user
            self.users.by_username[username] = uid
            self.users.by_email[email] = uid
            return _clone(user)

    def get_user(self, user_id: int) -> User:
        with self._lock:
            user = self.users.by_id.get(user_id)
            if user is None:
                raise NotFoundError("user {0} not found".format(user_id))
            return _clone(user)

    def list_users(self) -> List[User]:
        with self._lock:
            return [_clone(self.users.by_id[i]) for i in sorted(self.users.by_id)]

    def update_user(
        self,
        user_id: int,
        username: Optional[str] = None,
        email: Optional[str] = None,
        role: Optional[UserRole] = None,
    ) -> User:
        with self._lock:
            user = self.users.by_id.get(user_id)
            if user is None:
                raise NotFoundError("user {0} not found".format(user_id))

            new_username = user.username
            new_email = user.email
            new_role = user.role

            if username is not None:
                if not _is_nonempty_str(username):
                    raise ValidationError("username must be a non-empty string")
                new_username = username.strip()
            if email is not None:
                if not _is_nonempty_str(email) or "@" not in email:
                    raise ValidationError("invalid email")
                new_email = email.strip()
            if role is not None:
                if not isinstance(role, UserRole):
                    raise ValidationError("role must be a UserRole")
                new_role = role

            existing_username = self.users.by_username.get(new_username)
            if existing_username is not None and existing_username != user_id:
                raise DuplicateError("username already exists")
            existing_email = self.users.by_email.get(new_email)
            if existing_email is not None and existing_email != user_id:
                raise DuplicateError("email already exists")

            del self.users.by_username[user.username]
            del self.users.by_email[user.email]
            user.username = new_username
            user.email = new_email
            user.role = new_role
            self.users.by_username[new_username] = user_id
            self.users.by_email[new_email] = user_id
            return _clone(user)

    def delete_user(self, user_id: int) -> None:
        with self._lock:
            user = self.users.by_id.get(user_id)
            if user is None:
                raise NotFoundError("user {0} not found".format(user_id))

            for project in self.projects.by_id.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns a project")

            for tid in self.tasks.by_assignee.get(user_id, set()):
                task = self.tasks.by_id.get(tid)
                if task is not None and task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has an open task")

            del self.users.by_id[user_id]
            del self.users.by_username[user.username]
            del self.users.by_email[user.email]
            self.tasks.by_assignee.pop(user_id, None)

    # ------------------------------------------------------------------
    # Project management
    # ------------------------------------------------------------------
    def create_project(
        self,
        name: str,
        start_date: datetime,
        end_date: datetime,
        owner_id: int,
        description: str = "",
    ) -> Project:
        if not _is_nonempty_str(name):
            raise ValidationError("project name must be a non-empty string")
        if end_date < start_date:
            raise ValidationError("end_date cannot be before start_date")
        with self._lock:
            if owner_id not in self.users.by_id:
                raise NotFoundError("owner {0} not found".format(owner_id))
            pid = self._next_id()
            project = Project(
                id=pid,
                name=name.strip(),
                description=description or "",
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                created_at=self._now(),
            )
            self.projects.by_id[pid] = project
            self.tasks.by_project.setdefault(pid, set())
            self.messages.by_project.setdefault(pid, set())
            return _clone(project)

    def get_project(self, project_id: int) -> Project:
        with self._lock:
            project = self.projects.by_id.get(project_id)
            if project is None:
                raise NotFoundError("project {0} not found".format(project_id))
            return _clone(project)

    def list_projects(self) -> List[Project]:
        with self._lock:
            return [
                _clone(self.projects.by_id[i]) for i in sorted(self.projects.by_id)
            ]

    def update_project(
        self,
        project_id: int,
        name: Optional[str] = None,
        start_date: Optional[datetime] = None,
        end_date: Optional[datetime] = None,
        description: Optional[str] = None,
    ) -> Project:
        with self._lock:
            project = self.projects.by_id.get(project_id)
            if project is None:
                raise NotFoundError("project {0} not found".format(project_id))

            new_name = project.name
            new_start = project.start_date
            new_end = project.end_date
            new_desc = project.description

            if name is not None:
                if not _is_nonempty_str(name):
                    raise ValidationError("project name must be a non-empty string")
                new_name = name.strip()
            if start_date is not None:
                new_start = start_date
            if end_date is not None:
                new_end = end_date
            if description is not None:
                new_desc = description
            if new_end < new_start:
                raise ValidationError("end_date cannot be before start_date")

            project.name = new_name
            project.start_date = new_start
            project.end_date = new_end
            project.description = new_desc
            return _clone(project)

    def delete_project(self, project_id: int) -> None:
        with self._lock:
            project = self.projects.by_id.get(project_id)
            if project is None:
                raise NotFoundError("project {0} not found".format(project_id))

            for tid in list(self.tasks.by_project.get(project_id, set())):
                task = self.tasks.by_id.pop(tid, None)
                if task is not None and task.assignee_id is not None:
                    assignee_set = self.tasks.by_assignee.get(task.assignee_id)
                    if assignee_set is not None:
                        assignee_set.discard(tid)
                for mid in list(self.messages.by_task.get(tid, set())):
                    self.messages.by_id.pop(mid, None)
                self.messages.by_task.pop(tid, None)
            self.tasks.by_project.pop(project_id, None)

            for mid in list(self.messages.by_project.get(project_id, set())):
                self.messages.by_id.pop(mid, None)
            self.messages.by_project.pop(project_id, None)

            del self.projects.by_id[project_id]

    # ------------------------------------------------------------------
    # Task management
    # ------------------------------------------------------------------
    def create_task(
        self,
        project_id: int,
        title: str,
        assignee_id: Optional[int] = None,
        deadline: Optional[datetime] = None,
    ) -> Task:
        if not _is_nonempty_str(title):
            raise ValidationError("task title must be a non-empty string")
        with self._lock:
            project = self.projects.by_id.get(project_id)
            if project is None:
                raise NotFoundError("project {0} not found".format(project_id))
            if assignee_id is not None and assignee_id not in self.users.by_id:
                raise NotFoundError("assignee {0} not found".format(assignee_id))
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline cannot be before project start")

            tid = self._next_id()
            task = Task(
                id=tid,
                project_id=project_id,
                title=title.strip(),
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                started_at=None,
                completed_at=None,
                created_at=self._now(),
            )
            self.tasks.by_id[tid] = task
            self.tasks.by_project.setdefault(project_id, set()).add(tid)
            if assignee_id is not None:
                self.tasks.by_assignee.setdefault(assignee_id, set()).add(tid)
            return _clone(task)

    def get_task(self, task_id: int) -> Task:
        with self._lock:
            task = self.tasks.by_id.get(task_id)
            if task is None:
                raise NotFoundError("task {0} not found".format(task_id))
            return _clone(task)

    def list_tasks_by_project(self, project_id: int) -> List[Task]:
        with self._lock:
            if project_id not in self.projects.by_id:
                raise NotFoundError("project {0} not found".format(project_id))
            ids = self.tasks.by_project.get(project_id, set())
            return [_clone(self.tasks.by_id[i]) for i in sorted(ids)]

    def list_tasks_by_assignee(self, assignee_id: int) -> List[Task]:
        with self._lock:
            if assignee_id not in self.users.by_id:
                raise NotFoundError("user {0} not found".format(assignee_id))
            ids = self.tasks.by_assignee.get(assignee_id, set())
            return [_clone(self.tasks.by_id[i]) for i in sorted(ids)]

    def _set_assignee(self, task: Task, assignee_id: Optional[int]) -> None:
        if task.assignee_id is not None:
            current = self.tasks.by_assignee.get(task.assignee_id)
            if current is not None:
                current.discard(task.id)
        task.assignee_id = assignee_id
        if assignee_id is not None:
            self.tasks.by_assignee.setdefault(assignee_id, set()).add(task.id)

    def assign_task(self, task_id: int, assignee_id: int) -> Task:
        with self._lock:
            task = self.tasks.by_id.get(task_id)
            if task is None:
                raise NotFoundError("task {0} not found".format(task_id))
            if assignee_id not in self.users.by_id:
                raise NotFoundError("assignee {0} not found".format(assignee_id))
            self._set_assignee(task, assignee_id)
            return _clone(task)

    def reassign_task(self, task_id: int, new_assignee_id: int) -> Task:
        return self.assign_task(task_id, new_assignee_id)

    def unassign_task(self, task_id: int) -> Task:
        with self._lock:
            task = self.tasks.by_id.get(task_id)
            if task is None:
                raise NotFoundError("task {0} not found".format(task_id))
            self._set_assignee(task, None)
            return _clone(task)

    def set_deadline(
        self, task_id: int, deadline: Optional[datetime]
    ) -> Task:
        with self._lock:
            task = self.tasks.by_id.get(task_id)
            if task is None:
                raise NotFoundError("task {0} not found".format(task_id))
            if deadline is not None:
                project = self.projects.by_id.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError("deadline cannot be before project start")
            task.deadline = deadline
            return _clone(task)

    def update_status(self, task_id: int, status: TaskStatus) -> Task:
        if not isinstance(status, TaskStatus):
            raise ValidationError("status must be a TaskStatus")
        with self._lock:
            task = self.tasks.by_id.get(task_id)
            if task is None:
                raise NotFoundError("task {0} not found".format(task_id))

            now = self._now()
            if status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            elif status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            task.status = status
            return _clone(task)

    # ------------------------------------------------------------------
    # Messaging
    # ------------------------------------------------------------------
    def post_message(
        self,
        author_id: int,
        body: str,
        project_id: Optional[int] = None,
        task_id: Optional[int] = None,
        parent_id: Optional[int] = None,
        attachments: Optional[List[Tuple[str, bytes]]] = None,
    ) -> Message:
        with self._lock:
            if author_id not in self.users.by_id:
                raise NotFoundError("author {0} not found".format(author_id))
            if project_id is None and task_id is None:
                raise ValidationError("message needs a project or task target")
            if project_id is not None and task_id is not None:
                raise ValidationError("message needs exactly one target")
            if project_id is not None and project_id not in self.projects.by_id:
                raise NotFoundError("project {0} not found".format(project_id))
            if task_id is not None and task_id not in self.tasks.by_id:
                raise NotFoundError("task {0} not found".format(task_id))
            if parent_id is not None and parent_id not in self.messages.by_id:
                raise NotFoundError("parent message {0} not found".format(parent_id))

            raw_attachments = attachments or []
            has_body = isinstance(body, str) and bool(body.strip())
            if not has_body and not raw_attachments:
                raise ValidationError("message needs a body or attachments")

            now = self._now()
            attachment_objs = [
                Attachment(
                    filename=filename,
                    size=len(data),
                    uploaded_by=author_id,
                    uploaded_at=now,
                )
                for filename, data in raw_attachments
            ]

            mid = self._next_id()
            message = Message(
                id=mid,
                author_id=author_id,
                body=body,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=attachment_objs,
                created_at=now,
                edited_at=None,
            )
            self.messages.by_id[mid] = message
            if project_id is not None:
                self.messages.by_project.setdefault(project_id, set()).add(mid)
            if task_id is not None:
                self.messages.by_task.setdefault(task_id, set()).add(mid)
            return _clone(message)

    def edit_message(
        self, message_id: int, editor_id: int, new_body: str
    ) -> Message:
        with self._lock:
            message = self.messages.by_id.get(message_id)
            if message is None:
                raise NotFoundError("message {0} not found".format(message_id))
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit the message")
            has_body = isinstance(new_body, str) and bool(new_body.strip())
            if not has_body and not message.attachments:
                raise ValidationError("message needs a body or attachments")
            message.body = new_body
            message.edited_at = self._now()
            return _clone(message)

    def add_attachment(
        self, message_id: int, uploader_id: int, filename: str, data: bytes
    ) -> Message:
        with self._lock:
            message = self.messages.by_id.get(message_id)
            if message is None:
                raise NotFoundError("message {0} not found".format(message_id))
            if message.author_id != uploader_id:
                raise AuthorizationError("only the author may add attachments")
            if not _is_nonempty_str(filename):
                raise ValidationError("filename must be a non-empty string")
            message.attachments.append(
                Attachment(
                    filename=filename,
                    size=len(data),
                    uploaded_by=uploader_id,
                    uploaded_at=self._now(),
                )
            )
            return _clone(message)

    def list_messages_by_project(self, project_id: int) -> List[Message]:
        with self._lock:
            if project_id not in self.projects.by_id:
                raise NotFoundError("project {0} not found".format(project_id))
            ids = self.messages.by_project.get(project_id, set())
            return [_clone(self.messages.by_id[i]) for i in sorted(ids)]

    def list_messages_by_task(self, task_id: int) -> List[Message]:
        with self._lock:
            if task_id not in self.tasks.by_id:
                raise NotFoundError("task {0} not found".format(task_id))
            ids = self.messages.by_task.get(task_id, set())
            return [_clone(self.messages.by_id[i]) for i in sorted(ids)]

    def delete_message(self, message_id: int, requester_id: int) -> None:
        with self._lock:
            message = self.messages.by_id.get(message_id)
            if message is None:
                raise NotFoundError("message {0} not found".format(message_id))
            if message.author_id != requester_id:
                raise AuthorizationError("only the author may delete the message")
            del self.messages.by_id[message_id]
            if message.project_id is not None:
                target = self.messages.by_project.get(message.project_id)
                if target is not None:
                    target.discard(message_id)
            if message.task_id is not None:
                target = self.messages.by_task.get(message.task_id)
                if target is not None:
                    target.discard(message_id)

    # ------------------------------------------------------------------
    # Performance dashboard
    # ------------------------------------------------------------------
    def _assignee_tasks(self, user_id: int) -> List[Task]:
        ids = self.tasks.by_assignee.get(user_id, set())
        return [self.tasks.by_id[i] for i in ids if i in self.tasks.by_id]

    @staticmethod
    def _completion_seconds(task: Task) -> Optional[float]:
        if (
            task.status == TaskStatus.COMPLETED
            and task.started_at is not None
            and task.completed_at is not None
        ):
            return (task.completed_at - task.started_at).total_seconds()
        return None

    def get_completion_rate(self, user_id: int) -> float:
        with self._lock:
            if user_id not in self.users.by_id:
                raise NotFoundError("user {0} not found".format(user_id))
            tasks = self._assignee_tasks(user_id)
            if not tasks:
                return 0.0
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            return completed / len(tasks)

    def get_average_completion_time(self, user_id: int) -> Optional[float]:
        with self._lock:
            if user_id not in self.users.by_id:
                raise NotFoundError("user {0} not found".format(user_id))
            durations = [
                self._completion_seconds(t)
                for t in self._assignee_tasks(user_id)
            ]
            durations = [d for d in durations if d is not None]
            if not durations:
                return None
            return sum(durations) / len(durations)

    def submit_rating(
        self,
        rater_id: int,
        ratee_id: int,
        score: int,
        feedback: str = "",
        task_id: Optional[int] = None,
    ) -> Rating:
        with self._lock:
            if rater_id not in self.users.by_id:
                raise NotFoundError("rater {0} not found".format(rater_id))
            if ratee_id not in self.users.by_id:
                raise NotFoundError("ratee {0} not found".format(ratee_id))
            if rater_id == ratee_id:
                raise ConflictError("a user cannot rate themselves")
            if (
                not isinstance(score, int)
                or isinstance(score, bool)
                or score < 1
                or score > 5
            ):
                raise ValidationError("score must be an integer between 1 and 5")
            if task_id is not None and task_id not in self.tasks.by_id:
                raise NotFoundError("task {0} not found".format(task_id))

            rid = self._next_id()
            rating = Rating(
                id=rid,
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._now(),
            )
            self.performance.ratings_by_id[rid] = rating
            self.performance.ratings_by_ratee.setdefault(ratee_id, set()).add(rid)
            return _clone(rating)

    def _ratings_for(self, user_id: int) -> List[Rating]:
        ids = self.performance.ratings_by_ratee.get(user_id, set())
        return [self.performance.ratings_by_id[i] for i in sorted(ids)]

    def get_ratings_summary(self, user_id: int) -> Dict[str, Any]:
        with self._lock:
            if user_id not in self.users.by_id:
                raise NotFoundError("user {0} not found".format(user_id))
            ratings = self._ratings_for(user_id)
            count = len(ratings)
            average = (
                sum(r.score for r in ratings) / count if count else 0.0
            )
            return {
                "count": count,
                "average": average,
                "ratings": [_clone(r) for r in ratings],
            }

