    # ------------------------------------------------------------------
    # Reports
    # ------------------------------------------------------------------
    def project_progress_report(self, project_id: int) -> Dict[str, Any]:
        with self._lock:
            project = self.projects.by_id.get(project_id)
            if project is None:
                raise NotFoundError("project {0} not found".format(project_id))

            ids = self.tasks.by_project.get(project_id, set())
            tasks = [self.tasks.by_id[i] for i in sorted(ids)]
            total = len(tasks)

            status_counts = {status.value: 0 for status in TaskStatus}
            for task in tasks:
                status_counts[task.status.value] += 1

            completed = status_counts[TaskStatus.COMPLETED.value]
            completion_rate = completed / total if total else 0.0

            now = self._now()
            overdue = sum(
                1
                for t in tasks
                if t.deadline is not None
                and t.deadline < now
                and t.status != TaskStatus.COMPLETED
            )

            per_assignee: Dict[int, Dict[str, Any]] = {}
            for task in tasks:
                if task.assignee_id is None:
                    continue
                bucket = per_assignee.setdefault(
                    task.assignee_id,
                    {"total": 0, "completed": 0, "completion_rate": 0.0},
                )
                bucket["total"] += 1
                if task.status == TaskStatus.COMPLETED:
                    bucket["completed"] += 1
            for bucket in per_assignee.values():
                bucket["completion_rate"] = (
                    bucket["completed"] / bucket["total"]
                    if bucket["total"]
                    else 0.0
                )

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "project_name": project.name,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completion_rate,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def _user_performance_row(
        self, user_id: int, project_id: Optional[int]
    ) -> Dict[str, Any]:
        tasks = self._assignee_tasks(user_id)
        if project_id is not None:
            tasks = [t for t in tasks if t.project_id == project_id]
        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        completion_rate = completed / total if total else 0.0

        durations = [self._completion_seconds(t) for t in tasks]
        durations = [d for d in durations if d is not None]
        average_completion_time = (
            sum(durations) / len(durations) if durations else None
        )

        ratings = self._ratings_for(user_id)
        rating_count = len(ratings)
        rating_average = (
            sum(r.score for r in ratings) / rating_count if rating_count else 0.0
        )

        user = self.users.by_id[user_id]
        return {
            "user_id": user_id,
            "username": user.username,
            "total_tasks": total,
            "completed_tasks": completed,
            "completion_rate": completion_rate,
            "average_completion_time": average_completion_time,
            "rating_count": rating_count,
            "rating_average": rating_average,
        }

    def team_performance_report(
        self, project_id: Optional[int] = None
    ) -> Dict[str, Any]:
        with self._lock:
            if project_id is not None and project_id not in self.projects.by_id:
                raise NotFoundError("project {0} not found".format(project_id))

            if project_id is None:
                user_ids = sorted(self.users.by_id)
            else:
                user_ids_set = set()
                for tid in self.tasks.by_project.get(project_id, set()):
                    assignee = self.tasks.by_id[tid].assignee_id
                    if assignee is not None:
                        user_ids_set.add(assignee)
                user_ids = sorted(user_ids_set)

            rows = [
                self._user_performance_row(uid, project_id) for uid in user_ids
            ]
            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

