    # -- export -----------------------------------------------------------
    def export_report(
        self, report: Dict[str, Any], report_format: ReportFormat
    ) -> Any:
        if not isinstance(report, dict):
            raise ValidationError("report must be a dict")
        if not isinstance(report_format, ReportFormat):
            raise ValidationError("report_format must be a ReportFormat")

        if report_format == ReportFormat.CSV:
            return self._report_to_csv(report)
        return self._report_to_pdf(report)

    def _report_to_csv(self, report: Dict[str, Any]) -> str:
        buffer = io.StringIO()
        writer = csv.writer(buffer)
        report_type = report.get("report_type")

        if report_type == ReportType.TEAM_PERFORMANCE.value:
            headers = [
                "user_id",
                "username",
                "total_tasks",
                "completed_tasks",
                "completion_rate",
                "average_completion_time",
                "rating_count",
                "rating_average",
            ]
            writer.writerow(headers)
            for row in report.get("rows", []):
                writer.writerow([row.get(key, "") for key in headers])

        elif report_type == ReportType.PROJECT_PROGRESS.value:
            writer.writerow(["field", "value"])
            for key in (
                "project_id",
                "project_name",
                "total_tasks",
                "completion_rate",
                "overdue_tasks",
            ):
                writer.writerow([key, report.get(key, "")])
            for status_value, count in report.get("status_counts", {}).items():
                writer.writerow(["status_{0}".format(status_value), count])

        elif report_type == ReportType.INDIVIDUAL_PERFORMANCE.value:
            writer.writerow(["field", "value"])
            for key in (
                "user_id",
                "username",
                "total_tasks",
                "completed_tasks",
                "in_progress_tasks",
                "not_started_tasks",
                "completion_rate",
                "average_completion_time",
                "rating_count",
                "rating_average",
            ):
                writer.writerow([key, report.get(key, "")])

        else:
            writer.writerow(["field", "value"])
            for key, value in report.items():
                if isinstance(value, (list, dict)):
                    writer.writerow([key, len(value)])
                else:
                    writer.writerow([key, value])

        return buffer.getvalue()

    def _report_to_pdf(self, report: Dict[str, Any]) -> bytes:
        return _build_pdf(self._report_to_text_lines(report))

    @staticmethod
    def _report_to_text_lines(report: Dict[str, Any]) -> List[str]:
        lines = ["Report: {0}".format(report.get("report_type", "report"))]
        for key, value in report.items():
            if key == "report_type":
                continue
            if isinstance(value, (list, dict)):
                lines.append("{0}: {1} item(s)".format(key, len(value)))
            else:
                lines.append("{0}: {1}".format(key, value))
        return lines


# ---------------------------------------------------------------------------
# Minimal PDF writer
# ---------------------------------------------------------------------------
def _build_pdf(lines: List[str]) -> bytes:
    """Build a minimal, single-page PDF document from text lines."""

    text_ops = ["BT", "/F1 12 Tf", "50 750 Td", "14 TL"]
    for index, line in enumerate(lines or [""]):
        safe = (
            str(line)
            .replace("\\", "\\\\")
            .replace("(", "\\(")
            .replace(")", "\\)")
        )
        if index > 0:
            text_ops.append("T*")
        text_ops.append("({0}) Tj".format(safe))
    text_ops.append("ET")
    content = "\n".join(text_ops).encode("latin-1", "replace")

    objects = [
        b"<< /Type /Catalog /Pages 2 0 R >>",
        b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
        b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
        b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>",
        b"<< /Length "
        + str(len(content)).encode("latin-1")
        + b" >>\nstream\n"
        + content
        + b"\nendstream",
        b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
    ]

    pdf = bytearray(b"%PDF-1.4\n")
    offsets = []
    for number, body in enumerate(objects, start=1):
        offsets.append(len(pdf))
        pdf += "{0} 0 obj\n".format(number).encode("latin-1")
        pdf += body
        pdf += b"\nendobj\n"

    xref_position = len(pdf)
    total_objects = len(objects) + 1
    pdf += "xref\n0 {0}\n".format(total_objects).encode("latin-1")
    pdf += b"0000000000 65535 f \n"
    for offset in offsets:
        pdf += "{0:010d} 00000 n \n".format(offset).encode("latin-1")
    pdf += b"trailer\n"
    pdf += "<< /Size {0} /Root 1 0 R >>\n".format(total_objects).encode("latin-1")
    pdf += b"startxref\n"
    pdf += "{0}\n".format(xref_position).encode("latin-1")
    pdf += b"%%EOF"
    return bytes(pdf)
